import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp, checkRiderApproval } from "../services/api";
import { Container, Box, Typography, TextField, Button, Alert, CircularProgress } from "@mui/material";

export default function RiderLogin() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });
  const navigate = useNavigate();

  const handleCheckApproval = async () => {
    setMessage({ type: "", text: "" });

    if (!mobile || mobile.length !== 10) {
      setMessage({ type: "error", text: "Enter a valid 10-digit mobile number" });
      return;
    }

    try {
      setLoading(true);

      // ✅ Check if rider is approved
      const res = await checkRiderApproval(mobile);
      if (!res.data.approved) {
        setMessage({ type: "info", text: "Your account is still waiting for admin approval." });
        return; // ❌ stop here, do NOT send OTP
      }

      // ✅ Only send OTP if approved
      const otpRes = await sendOtp(mobile, "rider");
      if (otpRes.data.success) {
        setStep(2);
        setMessage({ type: "success", text: "OTP sent! Check your mobile." });
      } else {
        setMessage({ type: "error", text: otpRes.data.message });
      }
    } catch (err) {
      setMessage({ type: "error", text: err.response?.data?.message || "Server error" });
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setMessage({ type: "", text: "" });

    if (!otp || otp.length !== 6) {
      setMessage({ type: "error", text: "Enter the 6-digit OTP" });
      return;
    }

    try {
      setLoading(true);
      const res = await verifyOtp(mobile, otp, "rider");
      if (res.data.success) {
        localStorage.setItem("token", res.data.token || "dummy-token");
        localStorage.setItem("role", "rider");
        navigate("/rider-dashboard");
      } else {
        setMessage({ type: "error", text: res.data.message });
      }
    } catch (err) {
      setMessage({ type: "error", text: err.response?.data?.message || "Server error while verifying OTP" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Box sx={{ mt: 8, p: 4, border: "1px solid #ccc", borderRadius: 2, textAlign: "center" }}>
        <Typography variant="h5" gutterBottom>Rider Login</Typography>

        {message.text && <Alert severity={message.type} sx={{ mb: 2 }}>{message.text}</Alert>}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
              margin="normal"
            />
            <Button fullWidth variant="contained" sx={{ mt: 2 }} onClick={handleCheckApproval} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Continue"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              margin="normal"
            />
            <Button fullWidth variant="contained" sx={{ mt: 2 }} onClick={handleVerifyOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}
      </Box>
    </Container>
  );
}
